public static int countWords(String text) {
    ArrayList<String> words = new ArrayList<String>();

    for (int i=0;i<text.length();i++) {
        if (text.charAt(i) == ' ') {
            words.add(text.substring(i,i+1));
        }
    }

    return words.size();
}

